ActorFrame.InitCommand:
%function(self)
songName = GAMESTATE:GetCurrentSong():GetSongDir();
m_bl = 60/180 screen = SCREENMAN:GetTopScreen() sw = SCREEN_WIDTH sh = SCREEN_HEIGHT --shortcuts
-- The multiplier of the aft sprites' alpha value. aftMult = 1;
-- If the user is using a Nvidia graphic card, they have some issues with alphas of sprites. if tonumber(GAMESTATE:GetVersionDate()) >= 20170405 and string.find(string.lower(DISPLAY:GetVendor()), 'nvidia') or string.find(string.lower(PREFSMAN:GetPreference('LastSeenVideoDriver')), 'nvidia') then aftMult = 0.9; -- Setting the alpha multiplier to 0.9. end
end
